// components/TradingViewWidget.js
// Embeds the free TradingView chart using their lightweight widget script.

import React, { useEffect, useRef } from "react";

/**
 * TradingViewWidget
 * Props:
 *   symbol   – e.g. "BINANCE:BTCUSDT"
 *   interval – e.g. "60" (1 hour in TradingView notation)
 */
function TradingViewWidget({ symbol = "BINANCE:BTCUSDT", interval = "60" }) {
  const containerRef = useRef(null);

  useEffect(() => {
    // Remove old widget if re-rendering
    if (containerRef.current) {
      containerRef.current.innerHTML = "";
    }

    const script = document.createElement("script");
    script.src = "https://s3.tradingview.com/external-embedding/embed-widget-advanced-chart.js";
    script.type = "text/javascript";
    script.async = true;

    script.innerHTML = JSON.stringify({
      autosize: true,
      symbol: symbol,
      interval: interval,
      timezone: "Asia/Kolkata",
      theme: "dark",
      style: "1",
      locale: "en",
      enable_publishing: false,
      hide_top_toolbar: false,
      hide_legend: false,
      save_image: false,
      calendar: false,
      hide_volume: false,
      support_host: "https://www.tradingview.com",
    });

    if (containerRef.current) {
      containerRef.current.appendChild(script);
    }
    const currentRef = containerRef.current;
    return () => {
      if (currentRef) {
    currentRef.innerHTML = "";
}
    };
  }, [symbol, interval]);

  return (
    <div
      className="tradingview-widget-container"
      ref={containerRef}
      style={{ height: "480px", width: "100%" }}
    />
  );
}

export default TradingViewWidget;
